Title:
=if(WildMatch(vChannel,'*Retail','Brok*')>=1,

if(GetSelectedCount([Loan Officer]) > 0, GetFieldSelections([Loan Officer]),
	if(GetSelectedCount(Branch) > 0, 'Branch:' & GetFieldSelections(Branch),
    	'Select Branch or Loan Officer'))

,



if(GetSelectedCount([Account Executive]) > 0, GetFieldSelections([Account Executive]),
	if(GetSelectedCount([Broker Lender Name]) > 0, GetFieldSelections([Broker Lender Name]),
    	'Select Broker Lender Name or Account Executive')))

